class Solution {
public:
    int minimumBuckets(string street) {
        int result = 0;
        for (int i = 0; i < size(street); ++i) {
            if (street[i] != 'H' || (i && street[i - 1] == 'B')) {
                continue;
            }
            if (i + 1 < size(street) && street[i + 1] == '.') {
                street[i + 1] = 'B';
                ++result;
            } else if (i && street[i - 1] == '.') {
                street[i - 1] = 'B';
                ++result;
            } else {
                return -1;
            }
        }
        return result;
    }
};

# Time:  O(n)
# Space: O(n)

class Solution(object):
    def minimumBuckets(self, street):
        """
        :type street: str
        :rtype: int
        """
        result = 0
        street = list(street)
        for i, c in enumerate(street):
            if c != 'H' or (i and street[i-1] == 'B'):
                continue
            if i+1 < len(street) and street[i+1] == '.':
                street[i+1] = 'B'
                result += 1
            elif i and street[i-1] == '.':
                street[i-1] = 'B'
                result += 1
            else:
                return -1
        return result
